import type { ComponentPropsWithoutRef } from 'react';
import clsx from 'clsx';
import styles from './List.module.css';

type ListAs = 'ul' | 'ol';
type ListMarker = 'none' | 'disc' | 'decimal';
type ListGap = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';
type ListSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type ListTone = 'default' | 'muted' | 'subtle' | 'primary' | 'destructive';

type ListOwnProps = {
  as?: ListAs;
  marker?: ListMarker;
  gap?: ListGap;
  size?: ListSize;
  tone?: ListTone;
};

type UnorderedListProps = ListOwnProps &
  ComponentPropsWithoutRef<'ul'> & {
    as?: 'ul';
  };

type OrderedListProps = ListOwnProps &
  ComponentPropsWithoutRef<'ol'> & {
    as: 'ol';
  };

type ListProps = UnorderedListProps | OrderedListProps;
type ListItemProps = ComponentPropsWithoutRef<'li'>;

function List({
  as = 'ul',
  marker,
  gap = 'sm',
  size = 'md',
  tone = 'default',
  className,
  role,
  ...props
}: ListProps) {
  const Component = as;
  const resolvedMarker = marker ?? (as === 'ol' ? 'decimal' : 'disc');
  const markerMode = marker === undefined ? 'auto' : 'explicit';

  return (
    <Component
      data-slot="list-root"
      data-gap={gap}
      data-marker={resolvedMarker}
      data-marker-mode={markerMode}
      data-size={size}
      data-tone={tone}
      role={role ?? (resolvedMarker === 'none' ? 'list' : undefined)}
      className={clsx(styles.root, className)}
      {...props}
    />
  );
}

function ListItem({ className, ...props }: ListItemProps) {
  return <li data-slot="list-item" className={className} {...props} />;
}

export { List, ListItem };
export type { ListAs, ListGap, ListItemProps, ListMarker, ListProps, ListSize, ListTone };

@layer ui.components {
  .root {
    --_list-color: var(--list-color, var(--list-default-color, var(--color-foreground)));
    --_list-font-size: var(--list-font-size, var(--list-font-size-md, var(--text-md)));
    --_list-gap: var(--list-gap, var(--list-gap-sm, var(--spacing-2)));
    --_list-line-height: var(
      --list-line-height,
      var(--list-line-height-md, var(--line-height-text-md))
    );

    box-sizing: border-box;
    margin: 0;
    padding: 0;
    color: var(--_list-color);
    font-family: var(--list-font-family, var(--font-sans));
    font-size: var(--_list-font-size);
    font-weight: var(--list-font-weight, var(--weight-regular));
    line-height: var(--_list-line-height);
    letter-spacing: var(--list-letter-spacing, 0);
    list-style-position: outside;
    overflow-wrap: break-word;

    & > :where(li + li) {
      margin-block-start: var(--_list-gap);
    }

    & > :where(li)::marker {
      color: var(--list-marker-color, currentColor);
      font-weight: var(--list-marker-font-weight, inherit);
    }

    &[data-marker='none'] {
      padding-inline-start: 0;
      list-style: none;
    }

    &[data-marker='disc'],
    &[data-marker='decimal'] {
      padding-inline-start: var(--list-padding-x, var(--spacing-5));
    }

    &[data-marker='disc'] {
      list-style-type: disc;
    }

    &:is(ul)[data-marker='decimal'],
    &[data-marker='decimal'][data-marker-mode='explicit'] {
      list-style-type: decimal;
    }

    &[data-size='xs'] {
      --_list-font-size: var(--list-font-size, var(--list-font-size-xs, var(--text-xs)));
      --_list-line-height: var(
        --list-line-height,
        var(--list-line-height-xs, var(--line-height-text-xs))
      );
    }

    &[data-size='sm'] {
      --_list-font-size: var(--list-font-size, var(--list-font-size-sm, var(--text-sm)));
      --_list-line-height: var(
        --list-line-height,
        var(--list-line-height-sm, var(--line-height-text-sm))
      );
    }

    &[data-size='md'] {
      --_list-font-size: var(--list-font-size, var(--list-font-size-md, var(--text-md)));
      --_list-line-height: var(
        --list-line-height,
        var(--list-line-height-md, var(--line-height-text-md))
      );
    }

    &[data-size='lg'] {
      --_list-font-size: var(--list-font-size, var(--list-font-size-lg, var(--text-lg)));
      --_list-line-height: var(
        --list-line-height,
        var(--list-line-height-lg, var(--line-height-text-lg))
      );
    }

    &[data-size='xl'] {
      --_list-font-size: var(--list-font-size, var(--list-font-size-xl, var(--text-xl)));
      --_list-line-height: var(
        --list-line-height,
        var(--list-line-height-xl, var(--line-height-text-xl))
      );
    }

    &[data-tone='default'] {
      --_list-color: var(--list-color, var(--list-default-color, var(--color-foreground)));
    }

    &[data-tone='muted'] {
      --_list-color: var(--list-color, var(--list-muted-color, var(--color-muted-foreground)));
    }

    &[data-tone='subtle'] {
      --_list-color: var(--list-color, var(--list-subtle-color, var(--color-secondary-foreground)));
    }

    &[data-tone='primary'] {
      --_list-color: var(--list-color, var(--list-primary-color, var(--color-primary)));
    }

    &[data-tone='destructive'] {
      --_list-color: var(--list-color, var(--list-destructive-color, var(--color-destructive)));
    }
  }

  .root[data-gap='xs'] {
    --_list-gap: var(--list-gap, var(--list-gap-xs, var(--spacing-1)));
  }

  .root[data-gap='sm'] {
    --_list-gap: var(--list-gap, var(--list-gap-sm, var(--spacing-2)));
  }

  .root[data-gap='md'] {
    --_list-gap: var(--list-gap, var(--list-gap-md, var(--spacing-3)));
  }

  .root[data-gap='lg'] {
    --_list-gap: var(--list-gap, var(--list-gap-lg, var(--spacing-4)));
  }

  .root[data-gap='xl'] {
    --_list-gap: var(--list-gap, var(--list-gap-xl, var(--spacing-5)));
  }

  .root[data-gap='2xl'] {
    --_list-gap: var(--list-gap, var(--list-gap-2xl, var(--spacing-6)));
  }
}
